<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1" />
  <title>Personal Expense Tracker</title>
  <style>
    * { box-sizing: border-box; }
    body {
      font-family: system-ui, -apple-system, Segoe UI, Roboto, sans-serif;
      max-width: 720px;
      margin: 0 auto;
      padding: 1rem 1.25rem 2rem;
      color: #1a1a1a;
      line-height: 1.4;
    }
    h1 { font-size: 1.5rem; margin: 0 0 1rem; }
    h2 { font-size: 1.1rem; margin: 1.5rem 0 0.5rem; }
    form, .filters, .summary {
      border: 1px solid #ccc;
      border-radius: 6px;
      padding: 0.75rem 1rem;
      margin-bottom: 1rem;
      background: #fafafa;
    }
    label {
      display: block;
      font-size: 0.85rem;
      font-weight: 600;
      margin-bottom: 0.2rem;
    }
    .field { margin-bottom: 0.65rem; }
    input[type="number"],
    input[type="date"],
    input[type="text"],
    select {
      width: 100%;
      padding: 0.4rem 0.5rem;
      font-size: 1rem;
      border: 1px solid #bbb;
      border-radius: 4px;
    }
    .row-fields {
      display: grid;
      grid-template-columns: 1fr 1fr;
      gap: 0.65rem;
    }
    @media (max-width: 520px) {
      .row-fields { grid-template-columns: 1fr; }
    }
    button {
      cursor: pointer;
      font-size: 0.95rem;
      padding: 0.45rem 0.9rem;
      border-radius: 4px;
      border: 1px solid #888;
      background: #eee;
    }
    button:hover { background: #e0e0e0; }
    #add-expense {
      background: #2563eb;
      color: #fff;
      border-color: #1d4ed8;
      margin-top: 0.25rem;
    }
    #add-expense:hover { background: #1d4ed8; }
    #form-error {
      color: #b91c1c;
      font-size: 0.9rem;
      min-height: 1.2em;
      margin: 0.4rem 0 0;
    }
    #total-wrap {
      font-size: 1.15rem;
      font-weight: 700;
      margin: 0.5rem 0 1rem;
    }
    #expense-list {
      list-style: none;
      padding: 0;
      margin: 0;
    }
    .expense {
      display: flex;
      align-items: center;
      gap: 0.75rem;
      padding: 0.55rem 0.65rem;
      border: 1px solid #ddd;
      border-radius: 4px;
      margin-bottom: 0.4rem;
      background: #fff;
      flex-wrap: wrap;
    }
    .expense .exp-amount {
      font-weight: 700;
      min-width: 4.5rem;
    }
    .expense .exp-cat {
      background: #e5e7eb;
      padding: 0.15rem 0.45rem;
      border-radius: 3px;
      font-size: 0.85rem;
      text-transform: capitalize;
    }
    .expense .exp-date {
      color: #555;
      font-size: 0.9rem;
    }
    .expense .exp-note {
      flex: 1;
      color: #444;
      font-size: 0.9rem;
      min-width: 6rem;
    }
    .exp-del {
      margin-left: auto;
      background: #fee2e2;
      border-color: #fca5a5;
      color: #991b1b;
      padding: 0.3rem 0.55rem;
      font-size: 0.85rem;
    }
    .exp-del:hover { background: #fecaca; }
    .cat-totals {
      display: flex;
      flex-wrap: wrap;
      gap: 0.5rem;
    }
    .cat-total {
      background: #fff;
      border: 1px solid #ddd;
      border-radius: 4px;
      padding: 0.35rem 0.65rem;
      font-size: 0.9rem;
      text-transform: capitalize;
    }
    .empty-msg {
      color: #666;
      font-style: italic;
      margin: 0.5rem 0;
    }
    .expense[hidden] { display: none !important; }
  </style>
</head>
<body>
  <h1>Personal Expense Tracker</h1>

  <form id="expense-form" novalidate>
    <div class="row-fields">
      <div class="field">
        <label for="amount">Amount</label>
        <input type="number" id="amount" step="0.01" min="0" placeholder="0.00" />
      </div>
      <div class="field">
        <label for="category">Category</label>
        <select id="category">
          <option value="groceries">groceries</option>
          <option value="transport">transport</option>
          <option value="bills">bills</option>
          <option value="fun">fun</option>
        </select>
      </div>
    </div>
    <div class="row-fields">
      <div class="field">
        <label for="date">Date</label>
        <input type="date" id="date" />
      </div>
      <div class="field">
        <label for="note">Note (optional)</label>
        <input type="text" id="note" placeholder="Optional note" />
      </div>
    </div>
    <button type="submit" id="add-expense">Add expense</button>
    <p id="form-error" role="alert"></p>
  </form>

  <h2>Filters</h2>
  <div class="filters">
    <div class="row-fields">
      <div class="field">
        <label for="filter-category">Category</label>
        <select id="filter-category">
          <option value="all">all</option>
          <option value="groceries">groceries</option>
          <option value="transport">transport</option>
          <option value="bills">bills</option>
          <option value="fun">fun</option>
        </select>
      </div>
      <div class="field">
        <label for="filter-from">From</label>
        <input type="date" id="filter-from" />
      </div>
      <div class="field">
        <label for="filter-to">To</label>
        <input type="date" id="filter-to" />
      </div>
    </div>
  </div>

  <div id="total-wrap">Total: <span id="total">0.00</span></div>

  <h2>By category</h2>
  <div class="summary cat-totals" id="cat-totals">
    <div class="cat-total" data-cat="groceries">groceries: 0.00</div>
    <div class="cat-total" data-cat="transport">transport: 0.00</div>
    <div class="cat-total" data-cat="bills">bills: 0.00</div>
    <div class="cat-total" data-cat="fun">fun: 0.00</div>
  </div>

  <h2>Expenses</h2>
  <ul id="expense-list"></ul>
  <p id="empty-msg" class="empty-msg">No expenses yet.</p>

  <script>
    (function () {
      const STORAGE_KEY = 'expense-tracker-items';
      const CATEGORIES = ['groceries', 'transport', 'bills', 'fun'];

      const form = document.getElementById('expense-form');
      const amountInput = document.getElementById('amount');
      const categoryInput = document.getElementById('category');
      const dateInput = document.getElementById('date');
      const noteInput = document.getElementById('note');
      const formError = document.getElementById('form-error');
      const listEl = document.getElementById('expense-list');
      const emptyMsg = document.getElementById('empty-msg');
      const totalEl = document.getElementById('total');
      const filterCategory = document.getElementById('filter-category');
      const filterFrom = document.getElementById('filter-from');
      const filterTo = document.getElementById('filter-to');

      let expenses = loadExpenses();

      function loadExpenses() {
        try {
          const raw = localStorage.getItem(STORAGE_KEY);
          if (!raw) return [];
          const parsed = JSON.parse(raw);
          return Array.isArray(parsed) ? parsed : [];
        } catch (e) {
          return [];
        }
      }

      function saveExpenses() {
        localStorage.setItem(STORAGE_KEY, JSON.stringify(expenses));
      }

      function formatAmount(n) {
        return Number(n).toFixed(2);
      }

      function isVisible(exp) {
        const catFilter = filterCategory.value;
        if (catFilter !== 'all' && exp.category !== catFilter) return false;
        const from = filterFrom.value;
        const to = filterTo.value;
        if (from && exp.date < from) return false;
        if (to && exp.date > to) return false;
        return true;
      }

      function updateSummary() {
        let total = 0;
        const catSums = {};
        CATEGORIES.forEach(function (c) { catSums[c] = 0; });

        expenses.forEach(function (exp) {
          if (!isVisible(exp)) return;
          total += exp.amount;
          if (catSums[exp.category] !== undefined) {
            catSums[exp.category] += exp.amount;
          }
        });

        totalEl.textContent = formatAmount(total);

        CATEGORIES.forEach(function (c) {
          const el = document.querySelector('.cat-total[data-cat="' + c + '"]');
          if (el) {
            el.textContent = c + ': ' + formatAmount(catSums[c]);
          }
        });
      }

      function render() {
        listEl.innerHTML = '';
        // newest first: higher index / later id first; sort by date desc then id desc
        const sorted = expenses.slice().sort(function (a, b) {
          if (a.date !== b.date) return a.date < b.date ? 1 : -1;
          return b.id - a.id;
        });

        let anyRendered = false;
        let anyVisible = false;

        sorted.forEach(function (exp) {
          anyRendered = true;
          const li = document.createElement('li');
          li.className = 'expense';
          li.dataset.id = String(exp.id);

          const visible = isVisible(exp);
          if (!visible) {
            li.hidden = true;
          } else {
            anyVisible = true;
          }

          const amountSpan = document.createElement('span');
          amountSpan.className = 'exp-amount';
          amountSpan.textContent = formatAmount(exp.amount);

          const catSpan = document.createElement('span');
          catSpan.className = 'exp-cat';
          catSpan.textContent = exp.category;

          const dateSpan = document.createElement('span');
          dateSpan.className = 'exp-date';
          dateSpan.textContent = exp.date;

          const noteSpan = document.createElement('span');
          noteSpan.className = 'exp-note';
          noteSpan.textContent = exp.note || '';

          const delBtn = document.createElement('button');
          delBtn.type = 'button';
          delBtn.className = 'exp-del';
          delBtn.textContent = 'Delete';
          delBtn.addEventListener('click', function () {
            expenses = expenses.filter(function (e) { return e.id !== exp.id; });
            saveExpenses();
            render();
          });

          li.appendChild(amountSpan);
          li.appendChild(catSpan);
          li.appendChild(dateSpan);
          li.appendChild(noteSpan);
          li.appendChild(delBtn);
          listEl.appendChild(li);
        });

        emptyMsg.style.display = anyRendered ? 'none' : 'block';
        updateSummary();
      }

      form.addEventListener('submit', function (e) {
        e.preventDefault();
        const rawAmount = amountInput.value.trim();
        const amount = Number(rawAmount);
        const category = categoryInput.value;
        const date = dateInput.value;
        const note = noteInput.value.trim();

        if (
          rawAmount === '' ||
          !Number.isFinite(amount) ||
          amount <= 0 ||
          !date
        ) {
          formError.textContent = 'Please enter a positive amount and a date.';
          return;
        }

        formError.textContent = '';
        const id = Date.now() + Math.floor(Math.random() * 1000);
        expenses.push({
          id: id,
          amount: amount,
          category: category,
          date: date,
          note: note
        });
        saveExpenses();
        amountInput.value = '';
        noteInput.value = '';
        render();
      });

      filterCategory.addEventListener('change', render);
      filterFrom.addEventListener('change', render);
      filterTo.addEventListener('change', render);

      // Default date to today for convenience
      if (!dateInput.value) {
        const today = new Date();
        const yyyy = today.getFullYear();
        const mm = String(today.getMonth() + 1).padStart(2, '0');
        const dd = String(today.getDate()).padStart(2, '0');
        dateInput.value = yyyy + '-' + mm + '-' + dd;
      }

      render();
    })();
  </script>
</body>
</html>
